import "./styles/Login.css";
import { useNavigate } from "react-router-dom";
import { useState, useEffect } from "react";
import api from "../api/axios";

function Login() {
  const navigate = useNavigate();

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [role, setRole] = useState("Student");
  const [genre, setGenre] = useState("");
  const [error, setError] = useState("");

  // 🔐 Prevent login page if already logged in
  useEffect(() => {
    const isLoggedIn = localStorage.getItem("isLoggedIn");

    if (isLoggedIn === "true") {
      const savedRole = localStorage.getItem("role");

      if (savedRole === "Student") {
        navigate("/student-dashboard", { replace: true });
      } else if (savedRole === "Librarian") {
        navigate("/librarian-dashboard", { replace: true });
      } else if (savedRole === "Admin") {
        navigate("/admin-dashboard", { replace: true });
      }
    }
  }, [navigate]);

  const handleLogin = async () => {
    try {
      setError("");

      const data = { email, password, role };

      if (role === "Librarian") {
        data.genre = genre.trim().toLowerCase();
      }

      const res = await api.post("/auth/login", data);

      
      const { _id, name, role: userRole, genre: userGenre } = res.data;

      // ✅ SAVE LOGIN STATE
      localStorage.setItem("isLoggedIn", "true");
      localStorage.setItem("role", userRole);

      if (userRole === "Student") {
        navigate("/student-dashboard", { state: { name }, replace: true });

      } else if (userRole === "Librarian") {

        const fixedGenre =
          userGenre.charAt(0).toUpperCase() 
          userGenre.slice(1).toLowerCase();

        localStorage.setItem("genre", fixedGenre);

        navigate("/librarian-dashboard", {
          state: { genre: fixedGenre },
          replace: true
        });

      } else if (userRole === "Admin") {
        navigate("/admin-dashboard", { replace: true });
      }

    } catch (err) {
      setError("Invalid login credentials");
    }
  };

  return (
    <div className="login-wrapper">
      <div className="login-card">
        <h2>Login</h2>

        {error && <p className="error">{error}</p>}

        <input
          type="email"
          placeholder="University Email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
        />

        <input
          type="password"
          placeholder="Password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
        />

        <select value={role} onChange={(e) => setRole(e.target.value)}>
          <option>Student</option>
          <option>Librarian</option>
          <option>Admin</option>
        </select>

        {role === "Librarian" && (
          <input
            type="text"
            placeholder="Genre"
            value={genre}
            onChange={(e) => setGenre(e.target.value)}
          />
        )}

        <button className="login-btn" onClick={handleLogin}>
          Login
        </button>
      </div>
    </div>
  );
}

export default Login;
